from __future__ import annotations

import re
from typing import Any, Dict, List, Optional, Sequence, Tuple

from agent.documents.extraction.table_text import find_row_amount, last_amount_in_text

_MONEY = re.compile(
    r"\$\s?([\d,]+(?:\.\d{2})?)|\b([\d,]+(?:\.\d{2})?)\s*(?:USD|dollars?)\b",
    re.IGNORECASE,
)
_PERCENT = re.compile(r"(\d{1,3}(?:\.\d+)?)\s*%")
_SCHEDULE_E = re.compile(r"schedule\s+e", re.IGNORECASE)


def _money(text: str) -> Optional[float]:
    return last_amount_in_text(text)


def _safe_float(v: Any) -> Optional[float]:
    if v is None:
        return None
    try:
        return float(v)
    except (TypeError, ValueError):
        return None


def _find_labeled_amount(text: str, patterns: Sequence[str]) -> Optional[float]:
    lines = text.splitlines()
    for line in lines:
        low = line.lower()
        if any(p in low for p in patterns):
            amt = _money(line)
            if amt is not None:
                return amt
    flat = [line for line in lines if "|" in line]
    return find_row_amount(flat, patterns)


def _sum_rent_amounts(text: str) -> Optional[float]:
    """Sum monthly rent figures from rent-roll style lines."""
    total = 0.0
    count = 0
    for line in text.splitlines():
        low = line.lower()
        if "rent" in low or "monthly" in low:
            amt = _money(line)
            if amt is not None and 100 < amt < 5_000_000:
                total += amt
                count += 1
    return total if count >= 3 else None


def _parse_money(s: str) -> Optional[float]:
    try:
        return float(s.replace(",", ""))
    except ValueError:
        return None


def _sanitize_value_amount(val: Optional[float], *, min_amount: float = 100_000) -> Optional[float]:
    if val is None:
        return None
    try:
        f = float(val)
    except (TypeError, ValueError):
        return None
    return f if f > min_amount else None


def extract_appraisal_fields(text: str) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}

    # BBG / USPAP table: "Market Value - As Is ... $1,700,000"
    as_is_table = re.search(
        r"Market\s+Value\s*[-–]\s*As\s+Is[^\$]{0,200}\$([\d,]+)",
        text,
        re.IGNORECASE | re.DOTALL,
    )
    if as_is_table:
        val = _sanitize_value_amount(_parse_money(as_is_table.group(1)))
        if val is not None:
            facts["as_is_value"] = val

    as_complete_table = re.search(
        r"(?:Prospective\s+)?Market\s+Value[^\$]{0,120}As\s+Complete[^\$]{0,120}\$([\d,]+)",
        text,
        re.IGNORECASE | re.DOTALL,
    )
    if as_complete_table:
        ac = _sanitize_value_amount(_parse_money(as_complete_table.group(1)))
        if ac is not None:
            facts["as_complete_value"] = ac

    if "as_is_value" not in facts:
        for pat in ("as-is value", "as is value", "value conclusion", "appraised value"):
            val = _sanitize_value_amount(_find_labeled_amount(text, (pat,)))
            if val is not None:
                facts["as_is_value"] = val
                break

    addr_m = re.search(
        r"located at (\d+[-\d]*\s+[\w\s]+(?:Street|St|Road|Rd|Avenue|Ave|Boulevard|Blvd|Lane|Ln|Way|Drive|Dr))",
        text,
        re.IGNORECASE,
    )
    if addr_m:
        facts["property_address"] = addr_m.group(1).strip()

    purchase_m = re.search(
        r"acquired the subject[^\$]{0,60}\$([\d,]+)",
        text,
        re.IGNORECASE,
    )
    if purchase_m:
        facts["purchase_price"] = _parse_money(purchase_m.group(1))

    invested_m = re.search(
        r"invested\s+approximately\s*\$([\d,]+)",
        text,
        re.IGNORECASE,
    )
    if invested_m:
        facts["spent_to_date"] = _parse_money(invested_m.group(1))
        facts["rehab_invested"] = facts["spent_to_date"]

    remaining_m = re.search(
        r"remaining budget[^\$]{0,40}\$([\d,]+)",
        text,
        re.IGNORECASE,
    )
    if remaining_m:
        facts["remaining_budget_appraisal"] = _parse_money(remaining_m.group(1))

    sf_m = re.search(
        r"(\d{1,3}(?:,\d{3})*)\s+total square feet",
        text,
        re.IGNORECASE,
    )
    if sf_m:
        facts["building_sf"] = _parse_money(sf_m.group(1))

    if re.search(r"100%\s+pre-?leased", text, re.IGNORECASE) or re.search(
        r"100%\s+occupied", text, re.IGNORECASE
    ):
        facts["physical_occupancy"] = 1.0
        facts["economic_occupancy"] = 1.0
        if "pre-leased" in text.lower():
            facts["pre_leased"] = True

    tenant_count_m = re.search(
        r"100%\s+occupied by (\w+)\s+(?:professional\s+)?tenants",
        text,
        re.IGNORECASE,
    )
    if tenant_count_m:
        word = tenant_count_m.group(1).lower()
        word_map = {
            "eight": 8,
            "nine": 9,
            "ten": 10,
            "eleven": 11,
            "twelve": 12,
            "seventeen": 17,
            "sixteen": 16,
            "fifteen": 15,
            "fourteen": 14,
            "thirteen": 13,
        }
        if word in word_map:
            facts["tenant_count"] = word_map[word]

    rent_psf = re.search(r"\$([\d.]+)\s+per square foot", text, re.IGNORECASE)
    if rent_psf and facts.get("building_sf"):
        annual_rent = float(rent_psf.group(1)) * float(facts["building_sf"])
        facts["gross_potential_rent"] = annual_rent
        facts["rent_per_sf"] = float(rent_psf.group(1))

    ext_rent = re.search(
        r"lease exterior laydown space[^\$]{0,40}\$([\d,]+)\s+annually",
        text,
        re.IGNORECASE,
    )
    if ext_rent:
        facts["ancillary_rent_annual"] = _parse_money(ext_rent.group(1))
        if facts.get("gross_potential_rent"):
            facts["gross_potential_rent"] = float(facts["gross_potential_rent"]) + float(
                facts["ancillary_rent_annual"]
            )

    completion_m = re.search(
        r"(?:expected\s+)?completion date in (\w+\s+\d{4})",
        text,
        re.IGNORECASE,
    )
    if completion_m:
        facts["projected_stabilization"] = completion_m.group(1)

    condition_m = re.search(
        r"present in (\w+)\s+overall condition",
        text,
        re.IGNORECASE,
    )
    if condition_m:
        facts["building_condition"] = condition_m.group(1).lower()

    tenant_m = re.search(
        r"(\d+)\s+to\s+(\d+)\s+year terms?",
        text,
        re.IGNORECASE,
    )
    if tenant_m:
        low, high = int(tenant_m.group(1)), int(tenant_m.group(2))
        facts["wale_years"] = (low + high) / 2.0

    cap = _find_labeled_amount(text, ("cap rate", "capitalization rate"))
    if cap is not None and cap > 1:
        facts["cap_rate"] = cap / 100
    elif cap is not None and 0.01 < cap < 1:
        facts["cap_rate"] = cap
    noi = _find_labeled_amount(text, ("net operating income", "noi"))
    if noi is not None:
        facts["noi"] = noi
    elif facts.get("as_complete_value") and facts.get("cap_rate"):
        try:
            facts["noi"] = float(facts["as_complete_value"]) * float(facts["cap_rate"])
            facts["noi_source"] = "appraisal_cap_rate"
        except (TypeError, ValueError):
            pass

    state_m = re.search(
        r",\s*([A-Z]{2})\s+\d{5}",
        text,
    )
    if state_m:
        facts["property_state"] = state_m.group(1)

    return facts


def extract_rent_roll_fields(text: str) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    unit_patterns = (
        r"(\d+)\s*(?:units|unit)",
        r"total\s+units[:\s]*(\d+)",
        r"unit\s+count[:\s]*(\d+)",
    )
    for pat in unit_patterns:
        m = re.search(pat, text, re.IGNORECASE)
        if m:
            facts["total_units"] = int(m.group(1))
            break

    occ_m = re.search(
        r"(?:physical\s+)?occupancy[:\s]*(\d{1,3}(?:\.\d+)?)\s*%?",
        text,
        re.IGNORECASE,
    )
    if occ_m:
        occ = float(occ_m.group(1))
        facts["physical_occupancy"] = occ / 100 if occ > 1 else occ

    occupied_m = re.search(r"occupied[:\s]*(\d+)", text, re.IGNORECASE)
    if occupied_m and "total_units" in facts:
        occupied = int(occupied_m.group(1))
        facts["occupied_units"] = occupied
        if facts.get("total_units"):
            facts["physical_occupancy"] = occupied / int(facts["total_units"])

    gpr = _find_labeled_amount(text, ("gross potential rent", "gross rent", "total rent", "annual rent"))
    if gpr is None:
        gpr = _sum_rent_amounts(text)
    if gpr is not None:
        facts["gross_potential_rent"] = gpr

    vac = _find_labeled_amount(text, ("vacancy", "vacancy loss"))
    if vac is not None:
        facts["vacancy"] = vac

    conc = re.search(
        r"(?:largest|top)\s+tenant[:\s]*(\d{1,3}(?:\.\d+)?)\s*%?",
        text,
        re.IGNORECASE,
    )
    if conc:
        v = float(conc.group(1))
        facts["tenant_concentration"] = v / 100 if v > 1 else v

    tenant_count = len(re.findall(r"\b(?:tenant|lessee)\b", text, re.IGNORECASE))
    if tenant_count:
        facts["tenant_count"] = tenant_count
    return facts


def extract_t12_fields(text: str) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    egi = _find_labeled_amount(text, ("effective gross income", "egi", "total income"))
    if egi is not None:
        facts["effective_gross_income"] = egi
    gpr = _find_labeled_amount(text, ("gross potential rent", "gross rent", "rental income"))
    if gpr is not None:
        facts["gross_potential_rent"] = gpr
    opex = _find_labeled_amount(
        text,
        ("operating expenses", "total operating expenses", "total expenses", "opex"),
    )
    if opex is not None:
        facts["operating_expenses"] = opex
    noi = _find_labeled_amount(text, ("net operating income", "noi"))
    if noi is not None:
        facts["noi"] = noi
    elif egi is not None and opex is not None:
        facts["noi"] = egi - opex
    vac = _find_labeled_amount(text, ("vacancy", "vacancy loss"))
    if vac is not None:
        facts["vacancy"] = vac
    return facts


