"""Type-specific structured field extractors."""

from __future__ import annotations

import re
from typing import Any, Dict, Tuple

from agent.documents.document_qa.retrieval import extract_labeled_amounts
from agent.documents.extractors.cre_fields import (
    extract_appraisal_fields,
    extract_construction_fields,
    extract_credit_report_fields,
    extract_debt_schedule_fields,
    extract_hud_fields,
    extract_lease_fields,
    extract_pfs_from_text,
    extract_pfs_normalized,
    extract_pl_fields,
    extract_rent_roll_fields,
    extract_t12_fields,
    extract_tax_1040_fields,
    merge_cre_facts,
)
from agent.documents.extraction.table_text import (
    extract_bank_statement_fields,
    extract_pfs_fields_from_rows,
    extract_tax_schedule_fields,
)
from agent.documents.enums import DocumentType
from agent.documents.extraction.base import ExtractionResult

_MONEY = re.compile(
    r"\$\s?([\d,]+(?:\.\d{2})?)|\b([\d,]+(?:\.\d{2})?)\s*(?:USD|dollars?)\b",
    re.IGNORECASE,
)
_PERCENT = re.compile(r"(\d{1,3}(?:\.\d+)?)\s*%")
_DATE = re.compile(r"\b(\d{1,2}[/-]\d{1,2}[/-]\d{2,4})\b")
_FICO = re.compile(r"\b(?:fico|credit score)[:\s]*(\d{3})\b", re.IGNORECASE)


def extract_structured_fields(
    document_type: DocumentType,
    result: ExtractionResult,
) -> Tuple[Dict[str, Any], Dict[str, Dict[str, Any]]]:
    """
    Return (facts, field_sources) from raw extraction text.
    field_sources maps field_key -> {document_id placeholder handled upstream, page, excerpt}
    """
    text = result.full_text or ""
    facts: Dict[str, Any] = {}
    sources: Dict[str, Dict[str, Any]] = {}
    if not text.strip() and not result.structured_fields:
        return facts, sources

    excerpt = text[:240].replace("\n", " ")

    # Merge Azure layout table-derived fields first (highest confidence for tabular docs).
    _merge_azure_structured_fields(facts, sources, result, excerpt)

    table_rows = _table_rows_from_extraction(result)
    if table_rows:
        _merge_table_row_fields(facts, sources, document_type, table_rows, excerpt)

    if document_type in {DocumentType.BANK_STATEMENT, DocumentType.EXISTING_LOAN_STATEMENT}:
        amounts = _first_money_values(text, limit=3)
        if amounts and "amounts_found" not in facts:
            facts["amounts_found"] = amounts
            sources["amounts_found"] = {"page": 1, "excerpt": excerpt}

    if document_type in {DocumentType.PL_STATEMENT, DocumentType.BALANCE_SHEET, DocumentType.CASH_FLOW_STATEMENT}:
        amounts = _first_money_values(text, limit=5)
        if amounts and "line_item_amounts" not in facts:
            facts["line_item_amounts"] = amounts
            sources["line_item_amounts"] = {"page": 1, "excerpt": excerpt}

    if document_type == DocumentType.RENT_ROLL:
        merge_cre_facts(facts, extract_rent_roll_fields(text))
        for k in facts:
            if k not in sources and k != "document_type":
                sources[k] = {"page": 1, "excerpt": excerpt, "source": "cre_extractor"}

    if document_type == DocumentType.CREDIT_REPORT:
        merge_cre_facts(facts, extract_credit_report_fields(text))
        m = _FICO.search(text)
        if m and "credit_score_mention" not in facts:
            facts["credit_score_mention"] = int(m.group(1))
            sources["credit_score_mention"] = {"page": 1, "excerpt": excerpt}

    if document_type == DocumentType.PERSONAL_FINANCIAL_STATEMENT:
        merge_cre_facts(facts, extract_pfs_from_text(text))
        line_items = extract_labeled_amounts(text)
        if table_rows:
            row_items = extract_pfs_fields_from_rows(table_rows)
            line_items = {**row_items, **(line_items or {})}
        if line_items:
            existing = facts.get("pfs_line_items") or {}
            if isinstance(existing, dict):
                merged = {**line_items, **existing}
            else:
                merged = line_items
            merge_cre_facts(facts, extract_pfs_normalized(text, merged))
            facts["pfs_line_items"] = merged
            sources["pfs_line_items"] = {"page": 1, "excerpt": excerpt}
            for label, amount in merged.items():
                safe_key = re.sub(r"[^a-z0-9]+", "_", label).strip("_")
                if safe_key:
                    facts[f"pfs_{safe_key}"] = amount
                    sources[f"pfs_{safe_key}"] = {"page": 1, "excerpt": excerpt}

    if document_type in {DocumentType.PERSONAL_TAX_RETURN, DocumentType.BUSINESS_TAX_RETURN}:
        _merge_tax_text_fallbacks(facts, sources, text, excerpt)
        merge_cre_facts(facts, extract_tax_1040_fields(text))

    if document_type == DocumentType.PROPERTY_APPRAISAL:
        merge_cre_facts(facts, extract_appraisal_fields(text))
        sale_price = facts.get("as_is_value") or _find_appraisal_sale_price(text)
        if sale_price is not None:
            facts["appraisal_sale_price"] = sale_price
            sources["appraisal_sale_price"] = {"page": 1, "excerpt": excerpt}

    if document_type == DocumentType.T12_OPERATING_STATEMENT:
        merge_cre_facts(facts, extract_t12_fields(text))

    if document_type in {DocumentType.PL_STATEMENT, DocumentType.CASH_FLOW_STATEMENT}:
        merge_cre_facts(facts, extract_pl_fields(text))
        merge_cre_facts(facts, extract_t12_fields(text))

    if document_type == DocumentType.HUD_SETTLEMENT:
        merge_cre_facts(facts, extract_hud_fields(text))

    if document_type == DocumentType.LEASE_AGREEMENT:
        merge_cre_facts(facts, extract_lease_fields(text))

    if document_type == DocumentType.EXISTING_LOAN_STATEMENT:
        merge_cre_facts(facts, extract_hud_fields(text))

    if document_type in {
        DocumentType.CONSTRUCTION_BUDGET,
        DocumentType.COST_TO_COMPLETE,
        DocumentType.REHAB_BUDGET,
    }:
        prefix = "rehab" if document_type == DocumentType.REHAB_BUDGET else ""
        merge_cre_facts(facts, extract_construction_fields(text, prefix=prefix))

    if document_type == DocumentType.DEBT_SCHEDULE:
        merge_cre_facts(facts, extract_debt_schedule_fields(text))

    for k in facts:
        if k not in sources and not k.startswith("_"):
            sources.setdefault(k, {"page": 1, "excerpt": excerpt, "source": "cre_extractor"})

    dates = _DATE.findall(text)
    if dates:
        facts["dates_found"] = dates[:5]
        sources["dates_found"] = {"page": 1, "excerpt": excerpt}

    percents = [float(p) for p in _PERCENT.findall(text)[:5]]
    if percents:
        facts["percentages_found"] = percents
        sources["percentages_found"] = {"page": 1, "excerpt": excerpt}

    facts["document_type"] = document_type.value
    facts["extraction_method"] = result.method
    sources["document_type"] = {"page": 1, "excerpt": excerpt}
    return facts, sources


def _table_rows_from_extraction(result: ExtractionResult) -> list[list[str]]:
    structured = result.structured_fields or {}
    azure_rows = structured.get("azure_table_rows")
    if isinstance(azure_rows, list) and azure_rows:
        return [azure_rows]
    return []


def _merge_azure_structured_fields(
    facts: Dict[str, Any],
    sources: Dict[str, Dict[str, Any]],
    result: ExtractionResult,
    excerpt: str,
) -> None:
    structured = result.structured_fields or {}
    skip_keys = {"azure_table_count", "azure_table_rows", "tax_schedule", "bank_statement"}
    for key, value in structured.items():
        if key in skip_keys or key.startswith("_"):
            continue
        if key not in facts and value is not None:
            facts[key] = value
            sources[key] = {"page": 1, "excerpt": excerpt, "source": "azure_layout"}

    for nested_key in ("tax_schedule", "bank_statement"):
        nested = structured.get(nested_key)
        if isinstance(nested, dict):
            for key, value in nested.items():
                if key not in facts and value is not None:
                    facts[key] = value
                    sources[key] = {"page": 1, "excerpt": excerpt, "source": "azure_layout"}

    pfs_items = structured.get("pfs_line_items")
    if isinstance(pfs_items, dict):
        facts.setdefault("pfs_line_items", {})
        if isinstance(facts["pfs_line_items"], dict):
            facts["pfs_line_items"].update(pfs_items)
        for label, amount in pfs_items.items():
            safe_key = re.sub(r"[^a-z0-9]+", "_", str(label)).strip("_")
            if safe_key and f"pfs_{safe_key}" not in facts:
                facts[f"pfs_{safe_key}"] = amount
                sources[f"pfs_{safe_key}"] = {"page": 1, "excerpt": excerpt, "source": "azure_layout"}


def _merge_table_row_fields(
    facts: Dict[str, Any],
    sources: Dict[str, Dict[str, Any]],
    document_type: DocumentType,
    table_rows: list[list[str]],
    excerpt: str,
) -> None:
    if document_type in {DocumentType.PERSONAL_TAX_RETURN, DocumentType.BUSINESS_TAX_RETURN}:
        tax_facts = extract_tax_schedule_fields(table_rows)
        for key, value in tax_facts.items():
            if key not in facts:
                facts[key] = value
                sources[key] = {"page": 1, "excerpt": excerpt, "source": "table_rows"}

    if document_type == DocumentType.PERSONAL_FINANCIAL_STATEMENT:
        pfs_items = extract_pfs_fields_from_rows(table_rows)
        if pfs_items:
            existing = facts.get("pfs_line_items") or {}
            merged = {**existing, **pfs_items} if isinstance(existing, dict) else pfs_items
            facts["pfs_line_items"] = merged
            for label, amount in pfs_items.items():
                safe_key = re.sub(r"[^a-z0-9]+", "_", label).strip("_")
                if safe_key and f"pfs_{safe_key}" not in facts:
                    facts[f"pfs_{safe_key}"] = amount
                    sources[f"pfs_{safe_key}"] = {"page": 1, "excerpt": excerpt, "source": "table_rows"}

    if document_type == DocumentType.BANK_STATEMENT:
        bank_facts = extract_bank_statement_fields(table_rows)
        for key, value in bank_facts.items():
            if key not in facts:
                facts[key] = value
                sources[key] = {"page": 1, "excerpt": excerpt, "source": "table_rows"}


def _merge_tax_text_fallbacks(
    facts: Dict[str, Any],
    sources: Dict[str, Dict[str, Any]],
    text: str,
    excerpt: str,
) -> None:
    """Fallback when tables are sparse: search pipe-delimited or plain lines in full_text."""
    lines = text.splitlines()
