def _first_money_values(text: str, limit: int) -> list[float]:
    out: list[float] = []
    for m in _MONEY.finditer(text):
        raw = m.group(1) or m.group(2)
        if not raw:
            continue
        try:
            out.append(float(raw.replace(",", "")))
        except ValueError:
            continue
        if len(out) >= limit:
            break
    return out


def _find_appraisal_sale_price(text: str) -> float | None:
    patterns = (
        r"(?:sale|selling|market)\s+price[:\s]*\$?\s*([\d,]+(?:\.\d{2})?)",
        r"value\s+conclusion[:\s]*\$?\s*([\d,]+(?:\.\d{2})?)",
        r"appraised\s+value[:\s]*\$?\s*([\d,]+(?:\.\d{2})?)",
    )
    for pattern in patterns:
        match = re.search(pattern, text, re.IGNORECASE)
        if match:
            try:
                return float(match.group(1).replace(",", ""))
            except ValueError:
                continue
    return None
